# tasks.py
import os
from celery import Celery
from anthropic import Anthropic

app = Celery(
    "agent_tasks",
    broker=os.environ["REDIS_URL"],
    backend=os.environ["REDIS_URL"],
)

app.conf.update(
    task_serializer="json",
    result_serializer="json",
    accept_content=["json"],
    task_time_limit=300,          # hard kill after 5 min
    task_soft_time_limit=240,     # raise SoftTimeLimitExceeded at 4 min
    task_max_retries=3,
    task_default_retry_delay=30,  # seconds
    worker_prefetch_multiplier=1, # one task at a time per process
)

client = Anthropic()

@app.task(bind=True, name="run_agent")
def run_agent(self, prompt: str, system: str = "", context: dict = None):
    """Execute an agent task with automatic retry on transient errors."""
    try:
        messages = []
        if context:
            # Incorporate prior context as assistant turns
            for turn in context.get("history", []):
                messages.append(turn)
        messages.append({"role": "user", "content": prompt})

        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=4096,
            system=system or "You are a helpful assistant.",
            messages=messages,
        )
        return {
            "status": "completed",
            "output": response.content[0].text,
            "usage": {
                "input_tokens": response.usage.input_tokens,
                "output_tokens": response.usage.output_tokens,
            },
        }
    except Exception as exc:
        # Exponential backoff: 30s, 60s, 120s
        raise self.retry(exc=exc, countdown=30 * (2 ** self.request.retries))


# api.py — FastAPI producer
from fastapi import FastAPI
from pydantic import BaseModel
from tasks import run_agent

api = FastAPI()

class AgentRequest(BaseModel):
    prompt: str
    system: str = ""

@api.post("/jobs")
def submit_job(req: AgentRequest):
    result = run_agent.apply_async(
        kwargs={"prompt": req.prompt, "system": req.system},
        queue="agent",
    )
    return {"job_id": result.id, "status": "queued"}

@api.get("/jobs/{job_id}")
def get_job(job_id: str):
    result = run_agent.AsyncResult(job_id)
    if result.state == "PENDING":
        return {"status": "queued"}
    elif result.state == "STARTED":
        return {"status": "running"}
    elif result.state == "SUCCESS":
        return {"status": "completed", "result": result.get()}
    elif result.state == "FAILURE":
        return {"status": "failed", "error": str(result.result)}
    return {"status": result.state.lower()}

