from celery import Celery
import os

app = Celery(broker=os.environ["REDIS_URL"], backend=os.environ["REDIS_URL"])

app.conf.task_routes = {
    "tasks.run_realtime_agent": {"queue": "high_priority"},
    "tasks.run_batch_agent":    {"queue": "low_priority"},
}

@app.task(bind=True, name="tasks.run_realtime_agent", queue="high_priority")
def run_realtime_agent(self, payload: dict):
    """Short-deadline agent for user-facing requests."""
    from agent import execute
    return execute(payload, timeout=30)

@app.task(bind=True, name="tasks.run_batch_agent", queue="low_priority")
def run_batch_agent(self, payload: dict):
    """Long-running batch agent for background jobs."""
    from agent import execute
    return execute(payload, timeout=240)

# Launch workers with queue affinity:
# celery -A tasks worker -Q high_priority --concurrency=8 --loglevel=info
# celery -A tasks worker -Q low_priority,high_priority --concurrency=4 --loglevel=info
# Workers consuming high_priority are dedicated; low_priority workers also drain
# high_priority as a fallback so the queue never stalls.

# contract_processor.py — production task with checkpointing
import boto3, redis, json, os
from celery import Celery
from anthropic import Anthropic

app = Celery(broker=os.environ["REDIS_URL"], backend=os.environ["REDIS_URL"])
s3 = boto3.client("s3")
rdb = redis.from_url(os.environ["REDIS_URL"])
anthropic = Anthropic()

CHECKPOINT_TTL = 3600  # 1 hour

@app.task(bind=True, name="process_contract", max_retries=3, default_retry_delay=60)
def process_contract(self, job_id: str, s3_key: str, bucket: str):
    checkpoint_key = f"checkpoint:{job_id}"

    # Load checkpoint if this is a retry
    checkpoint = json.loads(rdb.get(checkpoint_key) or "{}")
    clauses = checkpoint.get("clauses")
    classifications = checkpoint.get("classifications")

    try:
        # Step 1: Extract text
        text = extract_text_from_s3(bucket, s3_key)

        # Step 2: Extract clauses (skip if checkpointed)
        if clauses is None:
            clauses = extract_clauses(text)
            checkpoint["clauses"] = clauses
            rdb.setex(checkpoint_key, CHECKPOINT_TTL, json.dumps(checkpoint))

        # Step 3: Classify risk (skip if checkpointed)
        if classifications is None:
            classifications = classify_clauses(clauses)
            checkpoint["classifications"] = classifications
            rdb.setex(checkpoint_key, CHECKPOINT_TTL, json.dumps(checkpoint))

        # Step 4: Generate summary
        summary = generate_summary(clauses, classifications)

        # Write final result and clean up checkpoint
        rdb.delete(checkpoint_key)
        return {"job_id": job_id, "summary": summary, "clause_count": len(clauses)}

    except Exception as exc:
        raise self.retry(exc=exc, countdown=60 * (2 ** self.request.retries))


def extract_clauses(text: str) -> list[dict]:
    response = anthropic.messages.create(
        model="claude-opus-4-5",
        max_tokens=8192,
        messages=[{
            "role": "user",
            "content": f"Extract all clauses from this contract as JSON:\n\n{text[:180000]}"
        }],
    )
    return json.loads(response.content[0].text)


def classify_clauses(clauses: list[dict]) -> list[dict]:
    response = anthropic.messages.create(
        model="claude-opus-4-5",
        max_tokens=4096,
        messages=[{
            "role": "user",
            "content": f"Classify these clauses by risk level:\n\n{json.dumps(clauses)}"
        }],
    )
    return json.loads(response.content[0].text)


def generate_summary(clauses, classifications) -> str:
    response = anthropic.messages.create(
        model="claude-opus-4-5",
        max_tokens=2048,
        messages=[{
            "role": "user",
            "content": f"Summarize this contract analysis:\nClauses: {json.dumps(clauses[:20])}\nRisk: {json.dumps(classifications[:20])}"
        }],
    )
    return response.content[0].text


def extract_text_from_s3(bucket: str, key: str) -> str:
    obj = s3.get_object(Bucket=bucket, Key=key)
    return obj["Body"].read().decode("utf-8", errors="replace")

